from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismListProjectsNode(BaseNode):
    name = "Prism: List Projects"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_output("projects", "list")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'projects': [], 'count': 0}
        try:
            projects = []
            projects_module = getattr(core, 'projects', None)
            if projects_module is not None:
                if hasattr(projects_module, 'getProjects'):
                    projects = projects_module.getProjects() or []
                else:
                    projects = getattr(projects_module, 'recentProjects', []) or []
            elif hasattr(core, 'getProjects'):
                projects = core.getProjects() or []
            elif hasattr(core, 'recentProjects'):
                projects = getattr(core, 'recentProjects', []) or []
            self.log_info(f"Found {len(projects)} project(s)")
            return {'projects': list(projects), 'count': len(projects)}
        except Exception as e:
            self.log_error(f"getProjects failed: {e}")
            return {'projects': [], 'count': 0}

def register_node():
    return PrismListProjectsNode
